from flask import Flask, session, request, jsonify
from functools import wraps
import redis
import os
import time

app = Flask(__name__)
app.secret_key = os.urandom(24)

# Connect to Redis
redis_client = redis.StrictRedis(host='localhost', port=6379, db=0, decode_responses=True)

# Secure Redis with AUTH
redis_client.execute_command('AUTH', 'your_redis_password')

# Session management using Redis
@app.before_request
def load_session():
    session_id = request.cookies.get('session_id')
    if session_id:
        session_data = redis_client.get(session_id)
        if session_data:
            session.update(eval(session_data))

@app.after_request
def save_session(response):
    session_id = request.cookies.get('session_id')
    if not session_id:
        session_id = os.urandom(24).hex()
        response.set_cookie('session_id', session_id)
    redis_client.set(session_id, dict(session))
    return response

# Caching decorator
def cache(expiration=60):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            cache_key = f"{f.__name__}:{args}:{kwargs}"
            cached_result = redis_client.get(cache_key)
            if cached_result:
                return jsonify(eval(cached_result))
            result = f(*args, **kwargs)
            redis_client.setex(cache_key, expiration, str(result))
            return jsonify(result)
        return decorated_function
    return decorator

# Example expensive database query
